"""Shared fixtures for pose module tests."""

import json
from pathlib import Path

import pytest

FIXTURES_DIR = Path(__file__).resolve().parents[2] / "fixtures" / "skeletons"


def _load_fixture(name: str) -> dict:
    path = FIXTURES_DIR / name
    with open(path, encoding="utf-8") as f:
        return json.load(f)


@pytest.fixture
def neutral_standing_fixture():
    """Full 32-joint neutral standing pose."""
    return _load_fixture("neutral_standing.json")


@pytest.fixture
def missing_joints_fixture():
    """Partial joint set with mixed tracking states."""
    return _load_fixture("missing_joints.json")


@pytest.fixture
def neutral_standing_kinect_frame(neutral_standing_fixture):
    """KinectFrame built from the neutral standing fixture."""
    from azure_kinect_comfyui.capture.models import (
        Joint,
        JointId,
        KinectFrame,
        TrackingState,
    )

    data = neutral_standing_fixture
    joints = {}
    for jid_str, jdata in data["joints_3d"].items():
        jid = int(jid_str)
        joints[jid] = Joint(
            joint_id=JointId(jid),
            position=tuple(jdata["position"]),
            state=TrackingState(jdata["state"]),
        )

    return KinectFrame(
        frame_id=1,
        timestamp_us=1_000_000,
        joints=joints,
        tracking_state=TrackingState.TRACKED,
        body_id=1,
    )


@pytest.fixture
def missing_joints_kinect_frame(missing_joints_fixture):
    """KinectFrame built from the missing joints fixture."""
    from azure_kinect_comfyui.capture.models import (
        Joint,
        JointId,
        KinectFrame,
        TrackingState,
    )

    data = missing_joints_fixture
    joints = {}
    for jid_str, jdata in data["joints_3d"].items():
        jid = int(jid_str)
        joints[jid] = Joint(
            joint_id=JointId(jid),
            position=tuple(jdata["position"]),
            state=TrackingState(jdata["state"]),
        )

    return KinectFrame(
        frame_id=2,
        timestamp_us=2_000_000,
        joints=joints,
        tracking_state=TrackingState.INFERRED,
        body_id=2,
    )

